read_verilog -formal <<EOT
module top;
(* anyseq *) wire [1:0] a;
wire [1:0] mask = 2'b01;
always @* assert({1'b0, a[0]} == (a & mask));
endmodule
EOT

proc -noopt
chformal -lower
write_btor design.btor2

sat -prove-asserts -verify                          # Returns UNSAT
exec -not-expect-stdout ^sat -- btormc design.btor2 # Returns UNSAT

